package org.blogs.Blogs.entity;import jakarta.persistence.*;import lombok.AllArgsConstructor;import lombok.Builder;import lombok.NoArgsConstructor;@Entity@Table(        name = "blog_like",        uniqueConstraints = @UniqueConstraint(columnNames = {"blog_id", "user_id"}))@NoArgsConstructor@AllArgsConstructor@Builderpublic class BlogLike {    @Id    @GeneratedValue(strategy = GenerationType.IDENTITY)    private Long id;    @ManyToOne    @JoinColumn(name = "blog_id", nullable = false)    private BlogPost blog;    @ManyToOne    @JoinColumn(name = "user_id")    private UserEntity user;}